{"command": "cd /tmp/sv-8407207fdfa04ddab28d9ce7b2261b7c

# Let me check if the addresses fall within .plt 
# .plt starts at 0x2ec500, .got.plt at 0x2f78e0, so .plt ends before 0x2f78e0
# 0x2f4b20 and 0x2f4c84 are within .plt range

# objdump the PLT section and grep for the entry containing our addresses  
aarch64-linux-gnu-objdump -d -j .plt libmonosgen-2.0.so 2>/dev/null | grep -E "^[0-9a-f]+ <" | awk -F'[< >]' '{
    addr = strtonum("0x"$1)
    if (addr <= 0x2f4b20 && addr >= 0x2f4b00) print "0x2f4b20 -> "$3
    if (addr <= 0x2f4c84 && addr >= 0x2f4c70) print "0x2f4c84 -> "$3
}'", "description": "Match PLT entries to symbols", "initial_wait": 15}

{"command": "cd /tmp/sv-8407207fdfa04ddab28d9ce7b2261b7c

# Dump all PLT entries to find those near our addresses
aarch64-linux-gnu-objdump -d -j .plt libmonosgen-2.0.so 2>/dev/null | grep "^[0-9a-f]" | head -5

echo "=== Trying full PLT dump around addresses ==="
aarch64-linux-gnu-objdump -d -j .plt libmonosgen-2.0.so 2>/dev/null | grep -E "<.*>:" | awk '{
    addr = strtonum("0x"substr($1, 1, length($1)))
    if (addr > 0x2f4a00 && addr < 0x2f4d00) print
}' 

echo "=== Total PLT entries ==="
aarch64-linux-gnu-objdump -d -j .plt libmonosgen-2.0.so 2>/dev/null | grep -c "<.*>:"", "description": "Dump PLT entries", "initial_wait": 15}

