cd /tmp/sv-8407207fdfa04ddab28d9ce7b2261b7c

# Find the closest symbols to these data addresses using the full symbol table from debug file
aarch64-linux-gnu-nm -n -C libmonosgen-2.0.so.dbg 2>/dev/null | awk '
    /^[0-9a-f]/ {
        addr = strtonum("0x"$1)
        name = $3
        for (i=4; i<=NF; i++) name = name " " $i

        if (addr <= 0x2f4b20) { prev1_addr = addr; prev1_name = name }
        if (addr <= 0x2f4c84) { prev2_addr = addr; prev2_name = name }
        if (addr > 0x2f4b20 && !found1) { printf "0x2f4b20: %s+0x%x (next: %s @ 0x%x)\n", prev1_name, 0x2f4b20-prev1_addr, name, addr; found1=1 }
        if (addr > 0x2f4c84 && !found2) { printf "0x2f4c84: %s+0x%x (next: %s @ 0x%x)\n", prev2_name, 0x2f4c84-prev2_addr, name, addr; found2=1 }
    }'

